### 1. MongoDB Schema

First, let's define our MongoDB schema for the rooms. We'll use Mongoose, an Object Data Modeling (ODM) library for MongoDB and Node.js.

```javascript
// models/Room.js
const mongoose = require('mongoose');

const RoomSchema = new mongoose.Schema({
    name: {
        type: String,
        required: true
    },
    capacity: {
        type: Number,
        required: true
    },
    status: {
        type: String,
        enum: ['Available', 'Occupied'],
        default: 'Available'
    }
});

module.exports = mongoose.model('Room', RoomSchema);
```

### 2. Express Backend

Next, we'll set up the Express server to handle CRUD operations on the rooms.

```javascript
// server.js
const express = require('express');
const mongoose = require('mongoose');
const Room = require('./models/Room');

const app = express();
app.use(express.json());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/room-management', {
    useNewUrlParser: true,
    useUnifiedTopology: true
}).then(() => console.log('MongoDB connected'))
  .catch(err => console.error(err));

// Routes
app.get('/api/rooms', async (req, res) => {
    const rooms = await Room.find();
    res.send(rooms);
});

app.post('/api/rooms', async (req, res) => {
    const { name, capacity, status } = req.body;
    const room = new Room({ name, capacity, status });
    await room.save();
    res.status(201).send(room);
});

app.put('/api/rooms/:id', async (req, res) => {
    const { name, capacity, status } = req.body;
    const updatedRoom = await Room.findByIdAndUpdate(req.params.id, { name, capacity, status }, { new: true });
    if (!updatedRoom) return res.status(404).send('Room not found');
    res.send(updatedRoom);
});

